import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { Search, Sun, Cloud, CloudRain, Wind, Droplets, Thermometer, CloudLightning, CloudSnow, Eye, Gauge } from 'lucide-react';
import './App.css';

const API_KEY = "1d30e0668b384c4d133dc45fe617b03b"; 

function App() {
  const [city, setCity] = useState('Visnagar');
  const [weatherData, setWeatherData] = useState(null);
  const [forecastData, setForecastData] = useState([]);
  const [hourlyData, setHourlyData] = useState([]);
  const [aqi, setAqi] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [themeClass, setThemeClass] = useState('theme-clear');

  const fetchWeather = async (searchCity) => {
    setLoading(true);
    setError('');
    try {
      // 1. Current Weather
      const currentRes = await axios.get(
        `https://api.openweathermap.org/data/2.5/weather?q=${searchCity}&units=metric&appid=${API_KEY}`
      );
      setWeatherData(currentRes.data);

      const { lat, lon } = currentRes.data.coord;

      // 2. Air Quality Index (AQI) API
      const aqiRes = await axios.get(
        `https://api.openweathermap.org/data/2.5/air_pollution?lat=${lat}&lon=${lon}&appid=${API_KEY}`
      );
      setAqi(aqiRes.data.list[0].main.aqi);

      // 3. 5-Day / 3-Hour Forecast
      const forecastRes = await axios.get(
        `https://api.openweathermap.org/data/2.5/forecast?q=${searchCity}&units=metric&appid=${API_KEY}`
      );

      // Hourly Forecast (પહેલા 5 ઇન્ટરવલ - આગામી 15 કલાક માટે)
      setHourlyData(forecastRes.data.list.slice(0, 5));

      // Daily Forecast (બપોરે 12 વાગ્યાનો ડેટા ફિલ્ટર કરવા)
      const dailyData = forecastRes.data.list.filter(item => item.dt_txt.includes("12:00:00"));
      setForecastData(dailyData);

      // Background Theme Selection
      const mainCondition = currentRes.data.weather[0].main;
      if (mainCondition === 'Clear') setThemeClass('theme-clear');
      else if (mainCondition === 'Clouds') setThemeClass('theme-clouds');
      else if (['Rain', 'Drizzle', 'Thunderstorm'].includes(mainCondition)) setThemeClass('theme-rain');
      else setThemeClass('theme-dark');

    } catch (err) {
      setError('સિટી મળ્યું નથી કે કનેક્શન પ્રોબ્લેમ છે.');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchWeather(city);
  }, []);

  const handleSearch = (e) => {
    e.preventDefault();
    if (city.trim()) fetchWeather(city);
  };

  const getWeatherIcon = (main, size = 50) => {
    switch (main) {
      case 'Clear': return <Sun className="weather-icon text-sun" size={size} />;
      case 'Clouds': return <Cloud className="weather-icon text-cloud" size={size} />;
      case 'Rain': case 'Drizzle': return <CloudRain className="weather-icon text-rain" size={size} />;
      case 'Thunderstorm': return <CloudLightning className="weather-icon text-thunder" size={size} />;
      case 'Snow': return <CloudSnow className="weather-icon text-snow" size={size} />;
      default: return <Sun className="weather-icon text-sun" size={size} />;
    }
  };

  const getAQIDescription = (index) => {
    const status = {
      1: { text: 'ખૂબ જ સરસ (Good)', color: '#00ffcc' },
      2: { text: 'મધ્યમ (Fair)', color: '#a855f7' },
      3: { text: 'સાધારણ (Moderate)', color: '#f59e0b' },
      4: { text: 'ખરાબ (Poor)', color: '#f87171' },
      5: { text: 'ખૂબ જ ખરાબ (Severe)', color: '#ef4444' }
    };
    return status[index] || { text: 'નથી ઉપલબ્ધ', color: '#fff' };
  };

  return (
    <div className={`app-wrapper ${themeClass}`}>
      <div className="sky-overlay"></div>

      <div className="weather-container">

        {/* Advanced Headers */}
        <div className="top-bar">
          <h2 className="brand-logo">Atmosphere<span>X</span></h2>
          <form onSubmit={handleSearch} className="search-box">
            <input 
              type="text" 
              placeholder="સિટીનું નામ લખો..." 
              value={city}
              onChange={(e) => setCity(e.target.value)}
            />
            <button type="submit"><Search size={18} /></button>
          </form>
        </div>

        {loading && <div className="loading-spinner">લાઇવ સેટેલાઇટ ડેટા કનેક્ટ થઈ રહ્યો છે...</div>}
        {error && <div className="error-display">{error}</div>}

        {weatherData && !loading && !error && (
          <div className="dashboard-grid">

            {/* Left Big Panel */}
            <div className="main-display-card">
              <div className="location-info">
                <h1>{weatherData.name}</h1>
                <p className="country-code">{weatherData.sys.country}</p>
              </div>
              <div className="hero-weather">
                {getWeatherIcon(weatherData.weather[0].main, 140)}
                <div className="temp-block">
                  <span className="big-temp">{Math.round(weatherData.main.temp)}°</span>
                  <span className="temp-unit">C</span>
                </div>
              </div>
              <p className="weather-status-text">{weatherData.weather[0].description}</p>

              {/* Hourly Section Inside Main Card */}
              <div className="hourly-section">
                <h5>આજની આગામી કલાકોની સ્થિતિ</h5>
                <div className="hourly-container">
                  {hourlyData.map((hour, idx) => (
                    <div key={idx} className="hourly-item">
                      <span>{hour.dt_txt.split(' ')[1].substring(0, 5)}</span>
                      {getWeatherIcon(hour.weather[0].main, 22)}
                      <span className="h-temp">{Math.round(hour.main.temp)}°</span>
                    </div>
                  ))}
                </div>
              </div>
            </div>

            {/* Right Side Complex Dash */}
            <div className="details-side">

              {/* Core Analytics Analytics */}
              <div className="widgets-grid">
                <div className="widget-card">
                  <div className="widget-header">
                    <Thermometer size={14} /> <span>FEELS LIKE</span>
                  </div>
                  <h3>{Math.round(weatherData.main.feels_like)}°C</h3>
                </div>

                <div className="widget-card">
                  <div className="widget-header">
                    <Droplets size={14} /> <span>HUMIDITY</span>
                  </div>
                  <h3>{weatherData.main.humidity}%</h3>
                </div>

                <div className="widget-card">
                  <div className="widget-header">
                    <Wind size={14} /> <span>WIND</span>
                  </div>
                  <h3>{weatherData.wind.speed} <span className="unit">m/s</span></h3>
                </div>

                <div className="widget-card">
                  <div className="widget-header">
                    <Eye size={14} /> <span>VISIBILITY</span>
                  </div>
                  <h3>{(weatherData.visibility / 1000).toFixed(1)} <span className="unit">km</span></h3>
                </div>

                {/* AQI Double Widget Span */}
                <div className="widget-card aqi-card">
                  <div className="widget-header">
                    <Gauge size={14} /> <span>AIR QUALITY (AQI)</span>
                  </div>
                  {aqi && (
                    <h3 style={{ color: getAQIDescription(aqi).color }}>
                      {getAQIDescription(aqi).text}
                    </h3>
                  )}
                </div>
              </div>

              {/* 5-Day Outlook with Progress bars look */}
              <div className="forecast-section">
                <h4>આગામી દિવસોની આગાહી</h4>
                <div className="forecast-list">
                  {forecastData.map((day, idx) => (
                    <div key={idx} className="forecast-row-card">
                      <span className="day-name">
                        {new Date(day.dt * 1000).toLocaleDateString('gu-IN', { weekday: 'long' })}
                      </span>
                      <div className="forecast-mid-wrapper">
                        {getWeatherIcon(day.weather[0].main, 24)}
                        <span className="rain-chance-label">{day.weather[0].main}</span>
                      </div>
                      <span className="forecast-temp-val">{Math.round(day.main.temp)}°C</span>
                    </div>
                  ))}
                </div>
              </div>

            </div>

          </div>
        )}
      </div>
    </div>
  );
}

export default App;
